class PiyiBannerCard extends StatelessWidget{const PiyiBannerCard({super.key,required this.icon,required this.title,required this.subtitle,required this.color,this.onTap});final IconData icon;final String title;final String subtitle;final Color color;final VoidCallback? onTap;@override Widget build(BuildContext context){final content=Container(padding:const EdgeInsets.all(PiyiSpacing.lg),decoration:BoxDecoration(color:color,borderRadius:BorderRadius.circular(PiyiRadius.xxl)),child:Row(children:[CircleAvatar(radius:28,backgroundColor:Colors.white.withOpacity(.2),child:Icon(icon,color:Colors.white,size:30)),const SizedBox(width:PiyiSpacing.md),Expanded(child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(title,style:const TextStyle(color:Colors.white,fontSize:20,fontWeight:FontWeight.w900)),const SizedBox(height:4),Text(subtitle,style:TextStyle(color:Colors.white.withOpacity(.92)))]))]));return onTap==null?content:InkWell(borderRadius:BorderRadius.circular(PiyiRadius.xxl),onTap:onTap,child:content);}}
